def range_summary(nums):
    if not nums:
        return ''

    nums = sorted(set(nums))
    result = []
    start = nums[0]

    for num in nums[1:]:
        if num != start + 1:
            if start == nums[0]:
                result.append(str(start))
            else:
                result.append(f'{start}-{nums[-2]}')
            start = num
    result.append(str(start))
    return ','.join(result)
